#include <iostream>

using namespace std;

int main()
{
    int scores[5] = {90, 85, 78, 92, 88};

    cout << "First: " << scores[0] << endl;
    cout << "Last: " << scores[4] << endl;

    return 0;
}

#include <iostream>

using namespace std;

int main()
{
    int scores[5] = {90, 85, 78, 92, 88};

    for (int i = 0; i < 5; i++)
    {
        cout << scores[i] << endl;
    }

    return 0;
}

int scores[5] = {90, 85, 78, 92, 88};

cout << scores[5];  // out of bounds! valid indices are only 0-4
cout << scores[-1]; // also out of bounds

